package com.example.knowledgecollector.web.externalsystem;
import com.example.knowledgecollector.application.externalsystem.*;import com.example.knowledgecollector.web.api.*;import jakarta.servlet.http.HttpServletRequest;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.Map;
@RestController @RequestMapping("/api/v1/external-systems") public class ExternalSystemController {private final ExternalSystemService service;public ExternalSystemController(ExternalSystemService service){this.service=service;}@GetMapping public ApiResponse<?>list(HttpServletRequest r){return ok(service.list(),r);}@PostMapping public ApiResponse<?>create(@RequestBody ExternalSystemCommand c,Authentication a,HttpServletRequest r){return ok(service.create(a.getName(),c),r);}@PutMapping("/{id}")public ApiResponse<?>update(@PathVariable long id,@RequestBody ExternalSystemCommand c,Authentication a,HttpServletRequest r){return ok(service.update(a.getName(),id,c),r);}@PostMapping("/{id}/enabled")public ApiResponse<?>enabled(@PathVariable long id,@RequestBody Map<String,Boolean>b,Authentication a,HttpServletRequest r){return ok(service.enable(a.getName(),id,Boolean.TRUE.equals(b.get("enabled"))),r);}@PostMapping("/{id}/test")public ApiResponse<?>test(@PathVariable long id,Authentication a,HttpServletRequest r){return ok(service.test(a.getName(),id),r);}@GetMapping("/{id}/open")public ApiResponse<?>open(@PathVariable long id,HttpServletRequest r){var v=service.get(id);return ok(Map.of("url",service.openUrl(id),"openMode",v.openMode()),r);}private<T>ApiResponse<T>ok(T d,HttpServletRequest r){return ApiResponse.success(d,(String)r.getAttribute(CorrelationIdFilter.ATTRIBUTE_NAME));}}
